-- ----------------------------------------------------------------------------
-- vw_project_metadata: Project overview
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_project_metadata WITH (security_invoker = ON) AS
SELECT
  t.project_id,
  t.name,                                                                       -- Effortlessly Invariant Rulesbooks (ERB)
  t.purpose,                                                                    -- Host a catalog of independent Effortless projects (rulebook-examples/<project>/), each a self-contained rulebook that fully captures one domain and selects the subset of platform substrates it needs. The platform proves that a rulebook is a complete spec: given just the rulebook, any frontier LLM can answer any question about the domain or produce a faithful implementation in any language / platform.
  t.architecture,                                                               -- Catalog of N independent Effortless projects under rulebook-examples/. Each project's rulebook JSON is its own hub / durable SSoT, with input spokes (Airtable, LLM edits, admin portal) and a project-chosen subset of the platform's 15 substrates as output spokes. The platform itself is one such project (effortless-platform/) describing ERB.
  t.entry_point,                                                                -- ./start.sh boots the admin portal (web UI) — local dev experience for any rulebook project
  t.portal_url,                                                                 -- http://localhost:7777 — admin portal served by run-web-portal.sh
  t.proxy_url,                                                                  -- http://localhost:4242 — ssotme-proxy serving substrate transpilers as HTTP routes
  t.repository_root                                                             -- effortlessly-invariant-rulesbooks/
FROM project_metadata t;

-- ----------------------------------------------------------------------------
-- vw_ontology_axioms: Positive-form invariants the project is built on. These are the load-bearing claims; if any one is dropped, the methodology no longer holds. FramingInvariants are mistakes that violate these axioms.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_ontology_axioms WITH (security_invoker = ON) AS
SELECT
  t.axiom_id,
  t.short_name,
  t.statement,                                                                  -- The axiom in one sentence
  t.why,                                                                        -- What collapses if you give this up
  t.implication,                                                                -- Concrete consequence for how the project is built / discussed
  t.status                                                                      -- active | revising | retired
FROM ontology_axioms t;

-- ----------------------------------------------------------------------------
-- vw_framing_invariants: Mistakes-to-avoid catalog. Each row is one wrong framing that has been caught and corrected, paired with the right framing and the axiom it violates. The portal surfaces these so future agents (and humans) can be re-grounded without rediscovering them.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_framing_invariants WITH (security_invoker = ON) AS
SELECT
  t.invariant_id,
  t.name,                                                                       -- Short title for grouping / display
  t.category,                                                                   -- substrate-equality | ssot-locality | hub-spoke-topology | category-error | fail-loud | role-confusion | naming | project-catalog | build-semantics | dialect-binding
  t.wrong_framing,                                                              -- The mistake verbatim
  t.correct_framing,                                                            -- The right framing
  t.why,                                                                        -- The reasoning that anchors it
  t.severity,                                                                   -- critical | important | nuance
  t.example_context,                                                            -- Where this came up — useful so future agents can recognise the situation
  t.status                                                                      -- active | retired
FROM framing_invariants t;

-- ----------------------------------------------------------------------------
-- vw_platform_features: The catalog of distinctive features the ERB platform offers. The rulebook is the formal SSoT for this list; the repo's README and per-feature README files MUST conform to these rows. Each feature has a one-line summary (the elevator pitch), a Tier (headline vs additional), a Priority (sort order within tier), and a ReadmeFilePath (where the long-form explanation lives — even if it's still a stub). IsReadmeStub is calculated so 'which READMEs are still missing' is a queryable fact, not a tribal one. Many features reference an OntologyAxiom — that's the axiom the feature operationalizes.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_platform_features WITH (security_invoker = ON) AS
SELECT
  t.feature_id,                                                                 -- Stable PK, e.g. feature-001
  t.name,                                                                       -- Full feature name as it appears in headings
  t.short_name,                                                                 -- Short identifier for cross-references (e.g. 'ADP', 'Hub-and-Spoke')
  t.tier,                                                                       -- headline | additional — drives the two README sections
  t.priority,                                                                   -- Sort order within tier (lower = higher up)
  t.one_line_summary,                                                           -- The elevator pitch — one sentence, no clauses about hypotheticals
  t.readme_file_path,                                                           -- Path to the per-feature README, relative to repo root. Hand-maintained but MUST conform to this row.
  t.readme_stub_content,                                                        -- The placeholder one-sentence body that ships in the README until it's fleshed out. Lets us hand-maintain READMEs while keeping the rulebook authoritative for the seed content.
  t.readme_length,                                                              -- Best-known character count of the README file on disk. Populated by a tooling pass; null means 'not yet measured'. Used to compute IsReadmeStub.
  t.status,                                                                     -- shipped | partial | planned — current implementation status
  calc_platform_features_is_readme_stub(t.feature_id) AS is_readme_stub         -- True if the README is still a placeholder (ReadmeLength is null OR < 400). Makes 'missing READMEs' a first-class query.
FROM platform_features t;

-- ----------------------------------------------------------------------------
-- vw_execution_substrates: Runtime environments that execute business rules derived from the rulebook
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_execution_substrates WITH (security_invoker = ON) AS
SELECT
  t.substrate_id,
  t.name,                                                                       -- Human-readable substrate name
  t.technology,                                                                 -- Language/platform (PostgreSQL, Python, Go, Excel, OWL, PlantUML, etc.)
  t.relative_path,                                                              -- Path within repo: execution-substrates/{technology}/
  t.injector_script,                                                            -- Code generation script: inject-into-{technology}.py
  t.test_script,                                                                -- Conformance test script: take-test.py
  t.transpiler_source,                                                          -- licensed-effortless-tool | local-injector | external. WHO BUILT THE GENERATOR — provenance, not trustworthiness. Replaces the old IsProduction column. See FramingInvariants.framing-003.
  t.maturity,                                                                   -- prototype | demonstrating | reference-quality — how complete THIS substrate's implementation is. Independent of TranspilerSource.
  t.expressive_completeness,                                                    -- full | partial-aggregation | partial-formula | shape-only — which formula classes this substrate can faithfully evaluate. A factual property of the substrate engine.
  t.can_be_answer_key,                                                          -- Can serve as the oracle (SSoT) in a conformance run if the user designates it. True for any substrate whose output is fully witnessable. NOT an authority ranking — see ax-002.
  t.determinism,                                                                -- deterministic | stochastic | externally-influenced — pure-function reproducibility class of the substrate
  t.runtime_kind,                                                               -- database | spreadsheet | binary | text-emit | graph | docs — what kind of artifact this substrate produces / runs as
  t.status,                                                                     -- Operational status (active, proof-of-concept, deprecated). Lifecycle, not trustworthiness.
  t.description                                                                 -- Purpose and capabilities
FROM execution_substrates t;

-- ----------------------------------------------------------------------------
