FROM orchestration_components t;

-- ----------------------------------------------------------------------------
-- vw_rulebook_source_spokes: Peer input spokes that can write into effortless-rulebook.json. The rulebook JSON is the durable SSoT; these are interchangeable sources.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_rulebook_source_spokes WITH (security_invoker = ON) AS
SELECT
  t.spoke_id,
  t.name,
  t.kind,                                                                       -- airtable | admin-portal | llm-direct | manual-json | reverse-sync
  t.direction,                                                                  -- input (writes into rulebook) | output (reads from rulebook) | bidirectional
  t.required,                                                                   -- False for all input spokes — any one is sufficient, none is required
  t.purpose,
  t.authority                                                                   -- On conflict, the rulebook JSON wins; spokes are the editors, not the SSoT
FROM rulebook_source_spokes t;

-- ----------------------------------------------------------------------------
-- vw_ssotme_proxy: Local HTTP transpiler server on localhost:4242. Each transpiler is an HTTP route; injectors are the route bodies. Used by `effortless build` to call substrate generators uniformly.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_ssotme_proxy WITH (security_invoker = ON) AS
SELECT
  t.route_id,
  t.route,                                                                      -- POST /{route-name}
  t.substrate_id,                                                               -- FK to ExecutionSubstrates.SubstrateId
  t.injector_script,                                                            -- Backing script that the route runs; null for upstream Effortless tools (e.g. airtable-to-rulebook)
  t.description
FROM ssotme_proxy t;

