-- ----------------------------------------------------------------------------
-- vw_rulebook_domains: Customer ontologies: each domain has its own rulebook + substrate generation. Domains form a TREE — ParentDomainId links a more-elaborate domain back to the simpler one it grew out of (e.g. Jessica ADVANCED ← Jessica BASIC). The UI uses this to present related rulebooks as a set rather than a flat list, and to drive 'next step in the progression' navigation.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_rulebook_domains WITH (security_invoker = ON) AS
SELECT
  t.domain_id,
  t.domain_name,
  t.relative_path,                                                              -- rulebook-examples/{domain}/ — each domain is a self-contained Effortless project
  t.rulebook_path,                                                              -- Path to effortless-rulebook.json within domain
  t.complexity_level,                                                           -- minimal, moderate, advanced, or philosophical
  t.table_count,
  t.key_features,                                                               -- Comma-separated: string concat, relationships, aggregations, IF logic, meta-ontology, etc.
  t.purpose,
  t.parent_domain_id,                                                           -- FK to RulebookDomains.DomainId — the simpler domain this one was derived from / builds on. Null for root-level demos (independent starting points). Lets the UI present rulebooks as a tree of related domains.
  t.progression_note                                                            -- One sentence describing what this domain ADDS over its parent — the specific concept the progression is meant to demonstrate at this step.
FROM rulebook_domains t;

