-- ----------------------------------------------------------------------------
-- vw_user_roles: Admin portal access tiers. Each role is a PERSONA with its own landing screen, tagline, and bespoke screen overrides (see RoleScreenHints). NOT a CRUD form — every role gets a UX shaped for what that person actually cares about. Also drives RLS policies that Postgres applies to portal writes.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_user_roles WITH (security_invoker = ON) AS
SELECT
  t.role_id,
  t.name,
  t.persona,                                                                    -- One-line description of WHO this role is — the kind of person who logs in as this role
  t.tagline,                                                                    -- Short motto shown on the role's landing screen — sets the mood
  t.primary_concerns,                                                           -- What this role spends time on. Comma-separated, used by the home screen to bubble these things up.
  t.color_theme,                                                                -- CSS accent colour for the role's pill / chrome — quick visual identity
  t.access_level,                                                               -- read | write | full-admin
  t.can_edit_rulebook,
  t.can_run_builds,
  t.can_access_tech_tools,                                                      -- Tech Tools nest = raw Postgres explorer, ssotme-proxy logs, conformance internals
  t.can_switch_projects,
  t.can_manage_users,
  t.description
FROM user_roles t;

-- ----------------------------------------------------------------------------
-- vw_app_permissions: RLS-style policy table: declarative per-role allow/deny on portal API endpoints and on Postgres tables. Generated into Postgres on portal bootstrap as RLS policies.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_app_permissions WITH (security_invoker = ON) AS
SELECT
  t.permission_id,
  t.resource,                                                                   -- Logical resource: rulebook.entity, rulebook.field, rulebook.formula, build, test, users, tech-tools.postgres, tech-tools.proxy
  t."action",                                                                   -- read | create | update | delete | execute
  t.allow,
  t.rls_predicate                                                               -- Postgres RLS USING clause (when applicable); null for endpoint-only checks
FROM app_permissions t;

-- ----------------------------------------------------------------------------
