-- ----------------------------------------------------------------------------
-- vw_rulebook_flavors: Classification of each demo rulebook under rulebook-examples/. Lets the UI group projects by what they're TEACHING — a tutorial ladder is a different beast from a computation-heavy ontology. Density numbers come from a static analysis of each rulebook (calculated/aggregation/lookup counts).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_rulebook_flavors WITH (security_invoker = ON) AS
SELECT
  t.flavor_id,
  t.sort_order,                                                                 -- Ascending integer; drives default display order in the portal. Lower = shown first. Tutorial-ladder projects sort before demos; demos before meta/graph.
  t.project_slug,                                                               -- Folder under rulebook-examples/ — also the active-domain.txt value
  t.display_name,
  t.flavor,                                                                     -- crud-template | computation-heavy | aggregation-heavy | graph-ontology | meta-rulebook | tutorial-ladder
  t.complexity,                                                                 -- minimal | basic | advanced
  t.entity_count,
  t.calculated_count,                                                           -- Number of calculated fields
  t.aggregation_count,
  t.lookup_count,
  t.learning_focus,                                                             -- What this demo is designed to teach
  t.good_answer_key_for                                                         -- Substrate(s) this demo makes a particularly good answer-key witness for — when applicable
FROM rulebook_flavors t;

-- ----------------------------------------------------------------------------
-- vw_field_type_taxonomy: Names every field-type the rulebook supports, with intent and example formula shape. Lets the UI explain what makes a calculated field different from a lookup field from an aggregation, instead of just showing a type tag.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_field_type_taxonomy WITH (security_invoker = ON) AS
SELECT
  t.type_id,
  t.type_name,                                                                  -- The string that appears in schema[].type
  t.intent,                                                                     -- What this type is FOR — one sentence
  t.example_formula,                                                            -- A representative formula or definition shape
  t.storage_mode,                                                               -- stored | derived-at-read | derived-at-write — where this field's value lives
  t.read_only_in_ui,                                                            -- True if the portal should never let users edit this field's value directly
  t.expressive_tier                                                             -- Which substrate ExpressiveCompleteness tier is required to faithfully evaluate this — full | partial-formula | partial-aggregation | shape-only
FROM field_type_taxonomy t;

-- ----------------------------------------------------------------------------
-- vw_role_screen_hints: Per-(role, screen) bespoke UX overrides. The base AppScreens row says WHAT the screen is; this table says HOW IT SHOULD FEEL FOR THIS ROLE. The hints are intentionally prescriptive enough that two different agents implementing the screen for the same role would land on the same flow.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_role_screen_hints WITH (security_invoker = ON) AS
SELECT
  t.hint_id,
  t.layout,                                                                     -- Override AppScreens.Layout for this role (e.g. Reviewer sees Tests as 'matrix-first', Ops sees Builds as 'last-build-banner')
  t.emphasis,                                                                   -- What this role wants to see first when they land here — the dominant visual element
  t.hide,                                                                       -- Comma-separated list of UI elements this role should not see on this screen
  t.primary_actions,                                                            -- Comma-separated, the buttons that should be prominent for this role
  t.implementation_hints                                                        -- Prescriptive description of the screen for this role. Detailed enough that two agents building it would land on the same flow.
FROM role_screen_hints t;

-- ----------------------------------------------------------------------------
-- vw_click_targets: Canonical in-app navigation affordances. Every clickable element in the portal should be listed here with where the click goes. Two agents implementing different screens would both consult this table to wire up cross-screen jumps. NOT the Explain-DAG — this is page-to-page navigation: 'Orders: 5' is clickable and goes to a page filtered to those 5 orders. NOT documentation-style 'learn more' links.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_click_targets WITH (security_invoker = ON) AS
SELECT
  t.click_id,
  t.from_kind,                                                                  -- What you're clicking on — entity-row,field-row,formula-cell,substrate-row,test-cell,role-pill,user-row,nav-card,count-number,fk-value,flavor-tag,framing-invariant,axiom
  t.from_context,                                                               -- Where this click affordance lives — e.g. 'home-card:substrates' or 'entity-detail:fk-field'
  t.to_path,                                                                    -- React-router-style path, with :param tokens that the caller fills in. e.g. /rulebook/entities/:entity?field=:field
  t.filter,                                                                     -- Query-string filter the target page should pre-apply
  t.story                                                                       -- Plain-English: 'Click Orders: 5 → see those 5 orders'. Anchor for implementer.
FROM click_targets t;

-- ----------------------------------------------------------------------------
-- vw_substrate_contract_phases: The three-phase contract every execution substrate implements. Inject is structural (schema → SDK), Execute is functional (compute), Grade is comparison. All three are 100% domain-agnostic — they translate whatever the rulebook defines without knowing what it means. Together with EvaluationSteps (the substeps within each phase) and EvaluationArtifacts (the JSON files that flow between phases), this forms the full evaluation subgraph: Phase → Steps → Artifacts.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_substrate_contract_phases WITH (security_invoker = ON) AS
SELECT
  t.phase_id,
  t."order",
  t.name,
  t.domain_agnostic,                                                            -- Whether this phase's code is generic across all rulebooks. All three are true by design.
  t.input,
  t.output,
  t.script_pattern,                                                             -- Filename pattern under each execution-substrates/<technology>/ folder.
  t.description,
  t.why_domain_agnostic,                                                        -- Explains how this phase remains generic — i.e. what it must NOT contain.
  t.input_artifact_id,                                                          -- FK to EvaluationArtifacts.ArtifactId — the canonical input artifact this phase consumes.
  t.output_artifact_id,                                                         -- FK to EvaluationArtifacts.ArtifactId — the canonical output artifact this phase produces.
  t.failure_mode                                                                -- What going wrong in this phase actually looks like — e.g. injector emits a domain word, execute calls a hand-written helper, grader hides field-level disagreement.
FROM substrate_contract_phases t;

-- ----------------------------------------------------------------------------
-- vw_evaluation_steps: Substeps within each SubstrateContractPhase. Inject, Execute, and Grade each decompose into a small number of concrete substeps the orchestrator executes in order. This is the layer below SubstrateContractPhases — it answers 'what specifically happens inside phase-execute?' Used by the admin portal's Tests screen to render the actual stages a substrate run goes through.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_evaluation_steps WITH (security_invoker = ON) AS
SELECT
  t.step_id,
  t.phase_id,                                                                   -- FK to SubstrateContractPhases.PhaseId.
  t."order",                                                                    -- Order within the parent phase.
  t.name,
  t.description,
  t.mechanism,                                                                  -- The actual code path — script file, function, or pipeline stage.
  t.invariant                                                                   -- A rule this step must preserve to remain domain-agnostic / conformance-preserving.
FROM evaluation_steps t;

-- ----------------------------------------------------------------------------
-- vw_evaluation_artifacts: The JSON / Markdown files that flow between SubstrateContractPhases. Each artifact is a contract: a file with a known schema produced by one phase and consumed by the next. This table is the artifact registry — what each file IS, where it lives, who writes it, who reads it. Together with SubstrateContractPhases.InputArtifactId/OutputArtifactId, this gives the evaluation pipeline a fully-witnessed data-flow graph.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_evaluation_artifacts WITH (security_invoker = ON) AS
SELECT
  t.artifact_id,
  t.name,
  t.format,                                                                     -- json | markdown | html | binary | source-tree
  t.path_pattern,                                                               -- Where the artifact lives on disk, with <placeholders> for variable parts.
  t.produced_by_phase_id,                                                       -- FK to SubstrateContractPhases.PhaseId — the phase that writes this artifact. Null for inputs that come from outside the evaluation pipeline (e.g. the rulebook itself).
  t.consumed_by_phase_id,                                                       -- FK to SubstrateContractPhases.PhaseId — the phase that reads this artifact. Null for terminal outputs (e.g. the human-facing report).
  t.derived_from,                                                               -- Plain-text description of how this artifact is derived — important for proving no substrate is privileged.
  t.description
FROM evaluation_artifacts t;

-- ----------------------------------------------------------------------------
-- vw_substrate_tradeoff_dimensions: The fixed taxonomy of dimensions used to characterize every substrate. Pro/con statements in SubstrateTradeoffs are scoped to one of these dimensions, so substrates can be compared apples-to-apples (e.g. 'who's fastest?' = filter SubstrateTradeoffs by DimensionId=dim-speed). Adding a dimension here means committing to fill it in for every substrate.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_substrate_tradeoff_dimensions WITH (security_invoker = ON) AS
SELECT
  t.dimension_id,
  t.name,
  t.description,
  t."order"                                                                     -- Display order in UI.
FROM substrate_tradeoff_dimensions t;

-- ----------------------------------------------------------------------------
-- vw_substrate_tradeoffs: Per-(Substrate × Dimension) Pro/Con/Note. The same fixed dimension set (see SubstrateTradeoffDimensions) is applied to every substrate, so 'why pick Postgres over Python?' or 'why does English cost so much?' is answerable by filtering this table. NOT a ranking — see ax-002 (no privileged substrate). Each row records a factual property along one comparable axis.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_substrate_tradeoffs WITH (security_invoker = ON) AS
SELECT
  t.tradeoff_id,
  t.substrate_id,                                                               -- FK to ExecutionSubstrates.SubstrateId.
  t.dimension_id,                                                               -- FK to SubstrateTradeoffDimensions.DimensionId.
  t.pro,                                                                        -- What this substrate does WELL along this dimension. Null if neutral or weak.
  t.con,                                                                        -- What this substrate does POORLY along this dimension. Null if neutral or strong.
  t.note                                                                        -- Additional context — e.g. quantitative observation, edge case, source of measurement.
FROM substrate_tradeoffs t;

-- ----------------------------------------------------------------------------
-- vw_fuzzy_grading_providers: LLM providers usable for fuzzy grading of the English substrate — the ONLY non-deterministic substrate. All other substrates execute formulas deterministically; English requires an LLM to interpret prose into computed values. Use low temperature (0.1) for repeatability.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_fuzzy_grading_providers WITH (security_invoker = ON) AS
SELECT
  t.provider_id,
  t.name,
  t.model,
  t.env_var,                                                                    -- Environment variable holding the API key. Null for local providers.
  t.determinism,                                                                -- 'non-deterministic' for all LLMs; low temperature reduces variance but does not eliminate it.
  t.typical_accuracy,                                                           -- Observed conformance on the English substrate against deterministic answer keys.
  t.speed_relative_to_deterministic,                                            -- Order-of-magnitude slowdown vs. a deterministic substrate like Python or Postgres.
  t.local_runtime,                                                              -- True if runnable without network.
  t.notes
FROM fuzzy_grading_providers t;

-- ----------------------------------------------------------------------------
-- vw_formula_dialects: Catalog of formula dialects that a rulebook can declare. Per-rulebook formula dialect is headline feature #6: each demo rulebook names which dialect it speaks (in _meta.formulaDialect), and substrates honor that declaration. The platform rulebook does not enumerate which functions a dialect supports — that lives in each demo rulebook's own formula definitions. This catalog only registers the dialects themselves.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_formula_dialects WITH (security_invoker = ON) AS
SELECT
  t.dialect_id,
  t.name,
  t.origin,                                                                     -- Where the dialect's surface syntax comes from (Excel, Airtable, etc.).
  t.field_ref_syntax,                                                           -- How a rulebook formula references another field.
  t.string_concat,                                                              -- How strings are concatenated in this dialect.
  t.case_sensitive,
  t.example_formula,
  t.primary_substrates,                                                         -- Substrates that have the richest support for this dialect.
  t.status,                                                                     -- active | experimental | deprecated
  t.notes
FROM formula_dialects t;

-- ----------------------------------------------------------------------------
-- vw_demo_narratives: Curated narratives that demonstrate ERB capabilities in motion: substrates 'follow along' as the rulebook changes. Two narrative styles coexist: (1) commit-sequence narratives (legacy) where a single demo rulebook evolves over commits; (2) cross-rulebook narratives (current) where the same demo is observed across DIFFERENT rulebooks side-by-side. Cross-rulebook supersedes commit-sequence because RulebookDomains now form a tree (ParentDomainId) — the progression is data, not git history.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_demo_narratives WITH (security_invoker = ON) AS
SELECT
  t.narrative_id,
  t."order",                                                                    -- Order within the narrative sequence.
  t.narrative_name,                                                             -- Name of the overall narrative this step belongs to.
  t.step_name,
  t.related_domain_id,                                                          -- FK to RulebookDomains.DomainId, when this step uses a specific demo rulebook.
  t.what_happens,
  t.key_lesson,
  t.observed_cost,                                                              -- Per-substrate cost observation (e.g. 'OWL 10s, English 5min').
  t.narrative_style,                                                            -- commit-sequence (legacy) | cross-rulebook (current) — how the steps are realized at demo time.
  t.status,                                                                     -- active | deprecated. Deprecated narratives are preserved for historical context but should not be used for new demos.
  t.superseded_by                                                               -- NarrativeName that replaces this one, when Status=deprecated.
FROM demo_narratives t;

-- ----------------------------------------------------------------------------
-- vw_glossary: Authoritative glossary for the ERB platform. Every term used in orchestration code, docs, the admin portal UI, or rulebook tables appears here EXACTLY ONCE, with a definition AND an ImplementedAs pointer back into this rulebook (or to source files when the implementation is code rather than data). If a term appears in repo prose but has no row here, that's a documentation bug. If a term has a row here but no ImplementedAs target, that's an architecture bug — every concept should be data, code, or a value.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_glossary WITH (security_invoker = ON) AS
SELECT
  t.term_id,
  t.term,                                                                       -- The canonical word/phrase as it appears in code and docs.
  t.category,                                                                   -- concept | role | artifact | phase | substrate | dimension | pattern | tool | location | invariant — what KIND of thing this term refers to.
  t.definition,                                                                 -- One precise sentence. Do not restate the term itself.
  t.implemented_as,                                                             -- Pointer to where this term is realized: 'table:X', 'column:X.Y', 'value:X.Y=Z', 'file:path/to/file', or 'axiom:axiom-id'. The promise is that a reader can follow this pointer and find the concept's actual realization.
  t.aliases,                                                                    -- Comma-separated other names that should resolve to this term. The canonical spelling is in Term; aliases redirect to it.
  t.notes
FROM glossary t;

-- ----------------------------------------------------------------------------
-- vw_rulebook_tags: Tag catalog for RulebookFlavors. Each tag has a color and emoji so it renders as a visible chip in the portal. Tags are flexible attributes — a flavor can have many tags. Browse/filter the flavors grid by any combination of tags.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_rulebook_tags WITH (security_invoker = ON) AS
SELECT
  t.tag_id,                                                                     -- Stable slug identifier, e.g. tag-postgres, tag-tutorial.
  t.label,                                                                      -- Short human-readable label shown as the chip text.
  t.category,                                                                   -- source | substrate | purpose | complexity | feature | flavor — groups tags in the filter panel.
  t.color,                                                                      -- Hex color for the chip background, e.g. #18BFFF.
  t.emoji,                                                                      -- Emoji or icon character shown as the leading icon on the chip.
  t.description                                                                 -- One sentence: what this tag means and when to apply it.
FROM rulebook_tags t;

-- ----------------------------------------------------------------------------
-- vw_flavor_tags: Junction table linking RulebookFlavors to RulebookTags (many-to-many via junction). A flavor can have any number of tags; a tag can apply to any number of flavors. The portal renders each flavor's tags as colored chip rows in the grid and uses them to drive the filter panel.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_flavor_tags WITH (security_invoker = ON) AS
SELECT
  t.flavor_tag_id,                                                              -- Stable unique ID for this flavor↔tag assignment.
  t.flavor,                                                                     -- FK to RulebookFlavors.FlavorId.
  t.tag                                                                         -- FK to RulebookTags.TagId.
FROM flavor_tags t;

-- ----------------------------------------------------------------------------
-- vw_claude_skills: The catalog of Claude Code skills that make up the effortless-claude skill set. Each skill is a loadable instruction set that pre-teaches Claude everything it needs to work in an ERB project — naming conventions, pipeline mechanics, formula semantics, etc. Skills are the answer to the LLM learning-curve problem: instead of every user teaching Claude from scratch, the learning is encoded once and loaded on demand. LocalMirrorPath is a derived artifact: clone-skills.sh pulls a live copy of each skill from the source repo so the docs/skills/ mirror stays current.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_claude_skills WITH (security_invoker = ON) AS
SELECT
  t.skill_id,                                                                   -- Stable PK, e.g. skill-001
  t.name,                                                                       -- Skill directory name, matches the slash command without the leading /
  calc_claude_skills_slash_command(t.skill_id) AS slash_command,                -- The slash command users invoke, e.g. /effortless-cmcc
  t.category,                                                                   -- theory | modeling | pipeline | setup | tooling | data | ecosystem | features
  t.one_line_summary,                                                           -- One sentence describing when to use this skill
  t.audience,                                                                   -- customer | general — who this skill is written for
  calc_claude_skills_local_mirror_path(t.skill_id) AS local_mirror_path,        -- Path to the derived local mirror of this skill. Generated by clone-skills.sh; DO NOT EDIT by hand.
  t.clone_url,                                                                  -- Raw GitHub URL from which clone-skills.sh pulls a fresh copy of this skill
  t.highlight_in_readme                                                         -- True if this skill should appear in the README skills highlights table — the ones most directly relevant to building with this repo
FROM claude_skills t;

